776	777	directus_operations	aecbd95c-e882-4ceb-acef-b806eaa25770	{"id":"aecbd95c-e882-4ceb-acef-b806eaa25770","name":"Format Payload","key":"payload","type":"exec","position_x":55,"position_y":1,"options":{"code":"/**\\n* Page Duplication Flow Function\\n* \\n* This function handles the duplication of a Directus page, including all its content blocks.\\n* It allows specifying a new title and permalink, or automatically creates them with \\"-Copy\\" suffix.\\n* The duplicated page is always set to draft status for review before publishing.\\n* \\n* @param {Object} data - Data object from Directus Flow\\n* @param {Object} data.$trigger.body - Optional data passed to the flow (new title/permalink)\\n* @param {Object} data.item - The original page being duplicated with all its properties\\n* @returns {Object} Modified page data for creating the duplicate\\n*/\\nmodule.exports = function(data) {\\n   // Get the data submitted with the flow trigger (if any)\\n   const triggerData = data.$trigger.body;\\n   \\n   // Get the full data of the existing page to duplicate\\n   const existingData = data.item;\\n   \\n   // Set the title for the duplicate:\\n   // - Use the provided title if it exists in the trigger data\\n   // - Otherwise, append \\"- Copy\\" to the original page title\\n   existingData.title = triggerData.title ?? existingData.title + ' - Copy';\\n   \\n   // Set the permalink for the duplicate:\\n   // - Use the provided permalink if it exists in the trigger data\\n   // - Otherwise, append \\"-copy\\" to the original permalink\\n   existingData.permalink = triggerData.permalink ?? existingData.permalink + '-copy';\\n   \\n   // Always set the duplicate page to draft status\\n   // This prevents accidental publishing of duplicate content\\n   existingData.status = 'draft';\\n   \\n   // Return the modified data to create the duplicate page\\n   // Note: Directus will handle copying all related blocks/components\\n   return existingData;\\n}"},"flow":"a23110e1-700b-41b8-9f9e-ca0998b84a76","date_created":"2025-05-04T14:20:32.310Z","user_created":"d56956bf-6ed0-465e-bb4a-ec9bde65c5f0"}	{"id":"aecbd95c-e882-4ceb-acef-b806eaa25770","name":"Format Payload","key":"payload","type":"exec","position_x":55,"position_y":1,"options":{"code":"/**\\n* Page Duplication Flow Function\\n* \\n* This function handles the duplication of a Directus page, including all its content blocks.\\n* It allows specifying a new title and permalink, or automatically creates them with \\"-Copy\\" suffix.\\n* The duplicated page is always set to draft status for review before publishing.\\n* \\n* @param {Object} data - Data object from Directus Flow\\n* @param {Object} data.$trigger.body - Optional data passed to the flow (new title/permalink)\\n* @param {Object} data.item - The original page being duplicated with all its properties\\n* @returns {Object} Modified page data for creating the duplicate\\n*/\\nmodule.exports = function(data) {\\n   // Get the data submitted with the flow trigger (if any)\\n   const triggerData = data.$trigger.body;\\n   \\n   // Get the full data of the existing page to duplicate\\n   const existingData = data.item;\\n   \\n   // Set the title for the duplicate:\\n   // - Use the provided title if it exists in the trigger data\\n   // - Otherwise, append \\"- Copy\\" to the original page title\\n   existingData.title = triggerData.title ?? existingData.title + ' - Copy';\\n   \\n   // Set the permalink for the duplicate:\\n   // - Use the provided permalink if it exists in the trigger data\\n   // - Otherwise, append \\"-copy\\" to the original permalink\\n   existingData.permalink = triggerData.permalink ?? existingData.permalink + '-copy';\\n   \\n   // Always set the duplicate page to draft status\\n   // This prevents accidental publishing of duplicate content\\n   existingData.status = 'draft';\\n   \\n   // Return the modified data to create the duplicate page\\n   // Note: Directus will handle copying all related blocks/components\\n   return existingData;\\n}"},"flow":"a23110e1-700b-41b8-9f9e-ca0998b84a76","date_created":"2025-05-04T14:20:32.310Z","user_created":"d56956bf-6ed0-465e-bb4a-ec9bde65c5f0"}	\N	\N
