823	824	directus_operations	d7f64e04-ab43-4d77-b8e8-379b41af2d3a	{"id":"d7f64e04-ab43-4d77-b8e8-379b41af2d3a","name":"Format Payload","key":"format_payload","type":"exec","position_x":73,"position_y":1,"options":{"code":"/**\\n * Automatic Redirect Generator for Content URL Changes\\n * \\n * This function generates redirect objects when published content URLs change.\\n * It works with both posts and pages collections to maintain SEO value\\n * and prevent broken links when content is moved or renamed.\\n */\\nconst map = {\\n  // Configuration for blog posts\\n  posts: {\\n    slugField: \\"slug\\",        // Field that contains the URL identifier for posts\\n    routePrefix: \\"/blog/\\",    // Prefix added to all post URLs (e.g., /blog/my-post)\\n  },\\n  // Configuration for pages\\n  pages: {\\n    slugField: \\"permalink\\",   // Field that contains the URL identifier for pages\\n    routePrefix: \\"\\",          // No prefix for pages (e.g., /about-us)\\n  },\\n};\\n\\n/**\\n * Flow function executed when content URL changes\\n * @param {Object} data - Data object from Directus Flow\\n * @param {Object} data.$trigger - Information about what triggered the flow\\n * @param {string} data.$trigger.collection - Collection name (posts/pages)\\n * @param {Object} data.$trigger.payload - New data being saved\\n * @param {Object} data.item - Previous version of the item before changes\\n * @returns {Object} Redirect configuration object\\n */\\nmodule.exports = function (data) {\\n  // Get the collection configuration based on whether this is a page or post\\n  const collection = map[data.$trigger.collection];\\n\\n  const oldSlug = data.item[collection.slugField];\\n  const newSlug = data.$trigger.payload[collection.slugField];\\n  \\n  // Build the old URL by combining the route prefix with the previous slug/permalink\\n  const oldUrl = `${collection.routePrefix}${oldSlug}`;\\n  \\n  // Build the new URL by combining the route prefix with the new slug/permalink\\n  const newUrl = `${collection.routePrefix}${newSlug}`;\\n    \\n  // Add a note\\n  const note = `Created by Redirect automation on ${new Date().toLocaleDateString(\\"en-US\\")} at ${new Date().toLocaleTimeString(\\"en-US\\")} when a ${data.$trigger.collection} ${collection.slugField} was updated from \\"${oldSlug}\\" to \\"${newSlug}\\"`\\n  \\n  // Return a redirect object that will be saved to the redirects collection\\n  return {\\n    response_code: 301,       // Permanent redirect (best for SEO)\\n    url_from: oldUrl,         // Where users were going before\\n    url_to: newUrl,           // Where they should be sent now\\n    note,\\n  };\\n};"},"resolve":"f6b8abc3-20bd-4d05-9bec-b7c759559e13","reject":null,"flow":"c62ceaa5-bd09-4158-8329-98792debc5d5","date_created":"2026-03-01T14:28:49.610Z","user_created":"316051e8-c301-48f8-88ca-dc014969f58c"}	{"resolve":"f6b8abc3-20bd-4d05-9bec-b7c759559e13","reject":null}	\N	\N
825	826	directus_operations	dff1a702-bcc0-4528-905e-309feb880111	{"id":"dff1a702-bcc0-4528-905e-309feb880111","name":"Format","key":"format","type":"exec","position_x":19,"position_y":18,"options":{"code":"/**\\n * Prepares email template data by matching trigger values with form fields\\n * @param {Object} trigger - The trigger object containing payload values\\n * @param {Object} form - The form object containing fields and email templates\\n * @returns {Array} Array of prepared email template objects\\n * @throws {Error} If required data is missing or invalid\\n */\\nfunction prepareEmailTemplateData(trigger, form) {\\n  // Validate input parameters\\n  if (!trigger?.payload?.values || !Array.isArray(trigger.payload.values)) {\\n    throw new Error('Invalid trigger payload values');\\n  }\\n  \\n  if (!form?.fields || !Array.isArray(form.fields)) {\\n    throw new Error('Invalid form fields');\\n  }\\n  \\n  if (!form?.emails || !Array.isArray(form.emails)) {\\n    throw new Error('Invalid form emails');\\n  }\\n\\n  // Create an object to store the field name-value pairs\\n  const data = {};\\n  \\n  // Iterate through the trigger values and match them with form fields\\n  trigger.payload.values.forEach(item => {\\n    if (!item || typeof item !== 'object') {\\n      throw new Error('Invalid trigger value item');\\n    }\\n\\n    // Ensure required properties exist\\n    if (!item.field && !item.field_name) {\\n      throw new Error('Missing field identifier in trigger value');\\n    }\\n    \\n    if (item.value === undefined) {\\n      throw new Error('Missing value in trigger value');\\n    }\\n\\n    // Find the corresponding field in the form\\n    const formField = form.fields.find(field => field.id === item.field);\\n    \\n    // If a matching field is found, use its name as the key\\n    if (formField && formField.name) {\\n      data[formField.name] = item.value;\\n    } else {\\n      // Fallback to using the field_name from the trigger if no match is found\\n      data[item.field_name || item.field] = item.value;\\n    }\\n  });\\n\\n  // Process and validate all email templates\\n  const emailTemplates = form.emails.map(email => {\\n    // Validate required email template properties\\n    if (!email.subject) {\\n      throw new Error('Missing email subject');\\n    }\\n    \\n    if (!email.message) {\\n      throw new Error('Missing email message template');\\n    }\\n    \\n    if (!email.to) {\\n      throw new Error('Missing email recipient');\\n    }\\n\\n    // Normalize 'to' field to always be an array\\n    const toField = Array.isArray(email.to) ? email.to : [email.to];\\n    \\n    // Validate each email address\\n    toField.forEach(recipient => {\\n      if (typeof recipient !== 'string' || !recipient.trim()) {\\n        throw new Error('Invalid email recipient');\\n      }\\n    });\\n\\n    return {\\n      to: toField,\\n      subject: email.subject,\\n      template: email.message,\\n      data: data\\n    };\\n  });\\n\\n  return emailTemplates;\\n}\\n\\nmodule.exports = function(data) {\\n  if (!data?.$trigger || !data?.form) {\\n    throw new Error('Missing required data');\\n  }\\n  \\n  return prepareEmailTemplateData(data.$trigger, data.form);\\n};"},"resolve":"fbf696ea-c6af-4230-8f62-c663beebd6d9","reject":null,"flow":"61757ab0-b139-4079-b5eb-4e05bb8142ac","date_created":"2026-03-01T14:28:49.638Z","user_created":"316051e8-c301-48f8-88ca-dc014969f58c"}	{"resolve":"fbf696ea-c6af-4230-8f62-c663beebd6d9","reject":null}	\N	\N
